VALUES
  ('social-worker-moex-05200', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '文獻回顧是研究中重要的步驟，下列敘述何者正確？①可以提供研究所需的理論背景，澄清與聚', '["目的在整理過往的研究發現，因此必須客觀、忠實，避免出現研究者自己的觀點", "在進行實證資料的收集前全部完成，以免研究方向走偏", "有助於將自己的研究發現整合進現 存的知識脈絡裡", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05201', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「將概念轉化為可觀察變項的過程」是下列那個選項的說明？', '["概念化", "操作化", "具象化", "變項化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05202', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關研究架構圖的敘述，下列何者錯誤？', '["依變項置於圖的右邊，自變項置於左邊，單向箭頭的線條表示兩端的變項有因果關係，起點的 變項為因，終點箭頭指向的變項為果", "單向箭頭的線條表示兩端的變項有因果關係，起點的變項為因，終點箭頭指向的變項為果", "雙向箭頭的線條表示兩端的變項相關", "沒有箭頭的線條表示兩端的變項沒有關係 情況：睡眠對健康至關重要。但研究發現，多數大學生睡眠品質不佳。葉教授想了解影響大學生睡 眠品質的因素，他從自己任教的大學裡，以系級名單隨機抽取20個班級，到這些班級發放問 卷，請全班同學填寫。問卷中，睡眠品質以「匹茲堡睡眠品質量表」（是由 7 題，每題 4 點 尺度的李克特（Likert）量表所構成，分數越高代表睡眠品質越差）來測量，其他變項包括受 訪者性別、每週運動時數、每天上網時數等。請依照上述資料，回答下列第5題至第8題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05203', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '此研究的抽樣方法為：', '["叢集抽樣法（cluster sampling）", "簡單隨機抽樣法（simple random sampling）", "便利抽樣法（convenience sampling）", "配額抽樣法（quota sampling）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05204', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究的分析單位是：', '["學校", "班級", "個人", "睡眠品質分數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05205', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究發現，「每天上網時數」與「睡眠品質」的相關係數 pearson r = 0.64（p=.002）。若顯著水 準 α=0.05，以下敘述何者正確？', '["「每天上網時數」與「睡眠品質」具有因果關係，兩者間的因果關係達統計上的顯著", "「每天上網時數」與「睡眠品質」，兩者相關達統計上的顯著", "「每天上網時數」和「睡眠品質」，沒有顯著相關", "「每天上網時數」可以解釋「睡眠品質」64%的變異量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05206', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究也發現，單就性別進行比較，女學生的睡眠品質顯著比男學生差，但控制了每週運動時數後', '["性 別跟睡眠品質有因果關係", "每週運動時數跟睡眠品質有因果關係", "性別跟睡眠品質是虛假 關係", "每週運動時數跟睡眠品質是間接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05207', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '數據顯示，一個地區居民的汽車擁有率越高，犯罪率越高。因此推論擁有汽車的人，犯罪比例比 較高。這樣的推論犯了什麼錯誤？', '["化約論（reductionism）", "過度概化（overgeneralization）", "霍桑效應（Hawthorne effect）", "生態謬誤（ecological fallacy）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "380b843b20b5", "answer_pdf_sha1": "bbe52e5a7c4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
